insert into public.publications (slug, category, title, gov_entity, official_status, version, source_url, summary, body, status, published_at)
values
('como-comprar-casa-ou-terreno-em-cabo-verde', 'compra', '{"pt":"Como comprar uma casa ou terreno em Cabo Verde","en":"How to buy a house or land in Cape Verde","nl":"Een huis of grond kopen in Kaapverdië"}'::jsonb, 'Conservatória do Registo Predial / Cartório Notarial (Registos, Notariado e Identificação — RNI)', 'summary', 1, 'https://boe.incv.cv', '{"pt":"Guia geral, passo a passo, para comprar casa ou terreno em Cabo Verde: verificação da titularidade na Conservatória, NIF, escritura pública perante notário, o imposto de transmissão cITI (que substitui o IUP desde 2026) e o registo predial; para terreno, a licença de construção.","en":"A step-by-step overview of buying a house or land in Cape Verde: title check at the Land Registry, NIF, public deed before a notary, the cITI transfer tax (replacing the IUP since 2026) and property registration; for land, the building permit.","nl":"Een stapsgewijs overzicht van het kopen van een huis of grond in Kaapverdië: titelcontrole bij het Kadaster, NIF, notariële akte, de cITI-overdrachtsbelasting (vervangt sinds 2026 de IUP) en kadastrale registratie; voor grond de bouwvergunning."}'::jsonb, '{"pt":"Nota: este é um resumo informativo da plataforma Djarvista; não constitui aconselhamento jurídico. Confirme sempre junto das entidades competentes.\n\nFACT: Em Cabo Verde, nacionais e estrangeiros têm, em regra, a mesma proteção legal na aquisição de imóveis, ao abrigo do Código Civil e do Código do Registo Predial.\n\nPassos:\n• ASSUMPTION/indicativo: Escolha o imóvel e negoceie o preço; é comum um contrato-promessa de compra e venda com sinal (frequentemente 10–20%). Confirme os termos com um advogado ou notário.\n• FACT: Verifique a titularidade na Conservatória do Registo Predial (RNI) através de uma certidão (Certidão de Teor), para confirmar que o vendedor é o legítimo proprietário e que não há ónus, hipotecas ou dívidas.\n• FACT: Necessita de um NIF (Número de Identificação Fiscal) para comprar e para operações bancárias — ver artigo específico.\n• FACT: A compra e venda formaliza-se por escritura pública, celebrada perante notário num Cartório Notarial.\n• FACT: Sobre a transmissão incide o cITI (Imposto sobre a Transmissão de Imóveis), que desde 1 de janeiro de 2026 substitui o antigo IUP (Lei n.º 54/X/2025). ASSUMPTION/indicativo: a taxa-regra indicada ronda 1%; confirme o valor atual e eventuais isenções com as Finanças/DNRE.\n• FACT: Após a escritura, registe a transmissão na Conservatória do Registo Predial.\n• ASSUMPTION/indicativo: Para terreno, antes de construir necessita de licença de construção, em regra emitida pela Câmara Municipal; confirme requisitos e o plano de urbanização aplicável.\n\nFontes / Sources / Bronnen: Boletim Oficial (boe.incv.cv); Casa do Cidadão (portondinosilhas.gov.cv); Finanças/DNRE (mf.gov.cv/web/dnre); Conservatória do Registo Predial / RNI. Verificação necessária / Verification required / Verificatie vereist.","en":"Note: this is an informational summary by the Djarvista platform; it is not legal advice. Always confirm with the competent authorities.\n\nFACT: In Cape Verde, nationals and foreigners generally enjoy the same legal protection when acquiring property, under the Civil Code and the Property Registration Code (Código do Registo Predial).\n\nSteps:\n• ASSUMPTION/indicative: Choose the property and negotiate the price; a promissory sale contract (contrato-promessa) with a deposit (often 10–20%) is common. Confirm terms with a lawyer or notary.\n• FACT: Check title at the Land Registry (Conservatória do Registo Predial / RNI) via a certificate (Certidão de Teor), to confirm the seller is the lawful owner and that there are no charges, mortgages or debts.\n• FACT: You need a NIF (tax number) to buy and for banking — see the dedicated article.\n• FACT: The sale is formalised by public deed (escritura pública) before a notary (Cartório Notarial).\n• FACT: The transfer is subject to the cITI (real-estate transfer tax), which since 1 January 2026 replaces the former IUP (Law No. 54/X/2025). ASSUMPTION/indicative: the indicated standard rate is around 1%; confirm the current rate and any exemptions with Finanças/DNRE.\n• FACT: After the deed, register the transfer at the Land Registry.\n• ASSUMPTION/indicative: For land, before building you need a construction permit, normally issued by the Municipality (Câmara Municipal); confirm requirements and the applicable urban plan.\n\nSources / Fontes / Bronnen: Boletim Oficial (boe.incv.cv); Casa do Cidadão (portondinosilhas.gov.cv); Finanças/DNRE (mf.gov.cv/web/dnre); Conservatória do Registo Predial / RNI. Verificação necessária / Verification required / Verificatie vereist.","nl":"Let op: dit is een informatieve samenvatting van het Djarvista-platform en vormt geen juridisch advies. Bevestig altijd bij de bevoegde instanties.\n\nFACT: In Kaapverdië genieten inwoners en buitenlanders in de regel dezelfde juridische bescherming bij de aankoop van vastgoed, op grond van het Burgerlijk Wetboek en het Kadasterwetboek (Código do Registo Predial).\n\nStappen:\n• ASSUMPTION/indicatief: Kies het pand en onderhandel over de prijs; een voorlopige koopovereenkomst (contrato-promessa) met een aanbetaling (vaak 10–20%) is gebruikelijk. Bevestig de voorwaarden met een advocaat of notaris.\n• FACT: Controleer de eigendomstitel bij het Kadaster (Conservatória do Registo Predial / RNI) via een uittreksel (Certidão de Teor), om te bevestigen dat de verkoper de rechtmatige eigenaar is en dat er geen lasten, hypotheken of schulden zijn.\n• FACT: U hebt een NIF (fiscaal nummer) nodig om te kopen en voor bankzaken — zie het aparte artikel.\n• FACT: De koop wordt geformaliseerd via een notariële akte (escritura pública) bij een notaris (Cartório Notarial).\n• FACT: Op de overdracht is de cITI (overdrachtsbelasting op vastgoed) van toepassing, die sinds 1 januari 2026 de vroegere IUP vervangt (Wet nr. 54/X/2025). ASSUMPTION/indicatief: het aangegeven standaardtarief ligt rond 1%; bevestig het actuele tarief en eventuele vrijstellingen bij Finanças/DNRE.\n• FACT: Registreer na de akte de overdracht bij het Kadaster.\n• ASSUMPTION/indicatief: Voor grond hebt u vóór de bouw een bouwvergunning nodig, doorgaans afgegeven door de gemeente (Câmara Municipal); bevestig de vereisten en het geldende bestemmingsplan.\n\nSources / Fontes / Bronnen: Boletim Oficial (boe.incv.cv); Casa do Cidadão (portondinosilhas.gov.cv); Finanças/DNRE (mf.gov.cv/web/dnre); Conservatória do Registo Predial / RNI. Verificação necessária / Verification required / Verificatie vereist."}'::jsonb, 'published', now()),
('nif-para-estrangeiros-em-cabo-verde', 'impostos', '{"pt":"NIF para estrangeiros em Cabo Verde","en":"NIF for foreigners in Cape Verde","nl":"NIF voor buitenlanders in Kaapverdië"}'::jsonb, 'Direção Nacional de Receitas do Estado (DNRE) — Ministério das Finanças / Casa do Cidadão', 'summary', 1, 'https://www.mf.gov.cv/web/dnre/solicitar-nif', '{"pt":"Como um estrangeiro obtém o NIF (Número de Identificação Fiscal) cabo-verdiano, necessário para comprar imóveis e abrir conta bancária, e onde o fazer: Casa do Cidadão e Direção Nacional de Receitas do Estado (DNRE).","en":"How a foreigner obtains the Cape Verdean NIF (tax identification number), needed to buy property and open a bank account, and where to do it: Casa do Cidadão and the National Directorate of State Revenue (DNRE).","nl":"Hoe een buitenlander het Kaapverdische NIF (fiscaal identificatienummer) verkrijgt, nodig om vastgoed te kopen en een bankrekening te openen, en waar: Casa do Cidadão en de Nationale Directie van Staatsinkomsten (DNRE)."}'::jsonb, '{"pt":"Nota: este é um resumo informativo da plataforma Djarvista; não constitui aconselhamento jurídico ou fiscal. Confirme sempre junto das entidades competentes.\n\nFACT: O NIF (Número de Identificação Fiscal) é atribuído em Cabo Verde pela Direção Nacional de Receitas do Estado (DNRE), do Ministério das Finanças.\n\nPara que serve:\n• FACT: O NIF é necessário para comprar imóveis, celebrar a escritura pública e pagar o imposto de transmissão (cITI).\n• ASSUMPTION/indicativo: Em regra, é também exigido para abrir conta bancária e contratar serviços; confirme os requisitos junto do banco.\n\nOnde e como:\n• FACT: O pedido pode ser feito presencialmente, de forma gratuita, nas Repartições de Finanças e nos balcões da Casa do Cidadão.\n• ASSUMPTION/indicativo: O estrangeiro apresenta, em regra, o passaporte (com validade mínima frequentemente indicada de 6 meses). Confirme a lista atual de documentos com a DNRE/Casa do Cidadão.\n• ASSUMPTION/indicativo: Estando a documentação em conformidade, o NIF costuma ser atribuído no momento do pedido.\n• ASSUMPTION/indicativo: Quem está no estrangeiro pode, em muitos casos, tratar do pedido através do portal da Casa do Cidadão (Porton di Nôs Ilha, portondinosilhas.gov.cv) ou por representante com procuração; confirme o procedimento aplicável.\n\nFontes / Sources / Bronnen: Finanças/DNRE (mf.gov.cv/web/dnre — Solicitar NIF); Casa do Cidadão (portondinosilhas.gov.cv); Boletim Oficial (boe.incv.cv). Verificação necessária / Verification required / Verificatie vereist.","en":"Note: this is an informational summary by the Djarvista platform; it is not legal or tax advice. Always confirm with the competent authorities.\n\nFACT: The NIF (tax identification number) is issued in Cape Verde by the National Directorate of State Revenue (Direção Nacional de Receitas do Estado, DNRE), part of the Ministry of Finance.\n\nWhat it is for:\n• FACT: The NIF is required to buy property, sign the public deed and pay the transfer tax (cITI).\n• ASSUMPTION/indicative: It is generally also required to open a bank account and contract services; confirm requirements with the bank.\n\nWhere and how:\n• FACT: The request can be made in person, free of charge, at the Finance offices (Repartições de Finanças) and at Casa do Cidadão counters.\n• ASSUMPTION/indicative: A foreigner normally presents a passport (a minimum validity of 6 months is often indicated). Confirm the current document list with DNRE/Casa do Cidadão.\n• ASSUMPTION/indicative: If the documents are in order, the NIF is usually issued at the time of request.\n• ASSUMPTION/indicative: People abroad can often apply through the Casa do Cidadão portal (Porton di Nôs Ilha, portondinosilhas.gov.cv) or via a representative with power of attorney; confirm the applicable procedure.\n\nSources / Fontes / Bronnen: Finanças/DNRE (mf.gov.cv/web/dnre — Solicitar NIF); Casa do Cidadão (portondinosilhas.gov.cv); Boletim Oficial (boe.incv.cv). Verificação necessária / Verification required / Verificatie vereist.","nl":"Let op: dit is een informatieve samenvatting van het Djarvista-platform en vormt geen juridisch of fiscaal advies. Bevestig altijd bij de bevoegde instanties.\n\nFACT: Het NIF (fiscaal identificatienummer) wordt in Kaapverdië toegekend door de Nationale Directie van Staatsinkomsten (Direção Nacional de Receitas do Estado, DNRE), onderdeel van het Ministerie van Financiën.\n\nWaarvoor dient het:\n• FACT: Het NIF is vereist om vastgoed te kopen, de notariële akte te tekenen en de overdrachtsbelasting (cITI) te betalen.\n• ASSUMPTION/indicatief: Het is doorgaans ook vereist om een bankrekening te openen en diensten af te nemen; bevestig de vereisten bij de bank.\n\nWaar en hoe:\n• FACT: De aanvraag kan kosteloos en persoonlijk worden gedaan bij de belastingkantoren (Repartições de Finanças) en aan de balies van Casa do Cidadão.\n• ASSUMPTION/indicatief: Een buitenlander toont in de regel een paspoort (vaak wordt een minimale geldigheid van 6 maanden aangegeven). Bevestig de actuele documentenlijst bij DNRE/Casa do Cidadão.\n• ASSUMPTION/indicatief: Als de documenten in orde zijn, wordt het NIF meestal op het moment van aanvraag toegekend.\n• ASSUMPTION/indicatief: Wie in het buitenland is, kan de aanvraag vaak doen via het portaal van Casa do Cidadão (Porton di Nôs Ilha, portondinosilhas.gov.cv) of via een vertegenwoordiger met volmacht; bevestig de toepasselijke procedure.\n\nSources / Fontes / Bronnen: Finanças/DNRE (mf.gov.cv/web/dnre — Solicitar NIF); Casa do Cidadão (portondinosilhas.gov.cv); Boletim Oficial (boe.incv.cv). Verificação necessária / Verification required / Verificatie vereist."}'::jsonb, 'published', now()),
('impostos-imobiliarios-iti-ipi-cabo-verde-2026', 'impostos', '{"pt":"Impostos imobiliários em Cabo Verde: cITI e cIPI (2026)","en":"Property taxes in Cape Verde: ITI and IPI (2026)","nl":"Vastgoedbelastingen in Kaapverdië: ITI en IPI (2026)"}'::jsonb, 'Direção Nacional das Receitas do Estado (DNRE) – Ministério das Finanças', 'summary', 1, 'https://www.dnre.gov.cv/', '{"pt":"Desde 1 de janeiro de 2026, o IUP sobre imóveis deu lugar a dois novos impostos: o ITI (na compra) e o IPI (propriedade anual), criados pelas Leis n.º 54/X/2025 e 55/X/2025. Resumo do que são, quem paga e quando — confirme taxas e prazos com a DNRE.","en":"Since 1 January 2026, the IUP on real estate has been replaced by two new taxes: the ITI (on purchase) and the IPI (annual ownership), created by Laws no. 54/X/2025 and 55/X/2025. A summary of what they are, who pays and when — confirm rates and deadlines with the DNRE.","nl":"Sinds 1 januari 2026 is de IUP op onroerend goed vervangen door twee nieuwe belastingen: de ITI (bij aankoop) en de IPI (jaarlijks eigendom), ingevoerd bij Wet nr. 54/X/2025 en 55/X/2025. Een samenvatting van wat ze zijn, wie betaalt en wanneer — bevestig tarieven en termijnen bij de DNRE."}'::jsonb, '{"pt":"FACTO: Desde 1 de janeiro de 2026, o Imposto Único sobre o Património (IUP) sobre imóveis foi substituído por dois novos códigos fiscais: o Código do Imposto sobre a Transmissão de Imóveis (ITI) e o Código do Imposto sobre a Propriedade de Imóveis (IPI). As siglas ''cITI'' e ''cIPI'' designam esses Códigos (''c'' = Código). Foram aprovados pelas Leis n.º 54/X/2025 e n.º 55/X/2025, de 6 de junho, e revogaram o Código do IUP.\n\nO que é cada um:\n• ITI (na compra): FACTO — incide sobre a transmissão onerosa de imóveis (compra e venda, permuta, etc.). Paga-o, em regra, o comprador; numa permuta ou partilha, quem recebe o bem de maior valor.\n• IPI (propriedade anual): FACTO — incide sobre a titularidade do imóvel; é devido anualmente pelo proprietário, com base no valor patrimonial.\n\nTaxas (confirmar): valores noticiados apontam ITI ~1% (agravado até 3% em regimes privilegiados) e IPI ~0,1% sobre prédios e ~0,15% sobre terrenos, com agravamentos para imóveis devolutos/degradados. Confirme as taxas, escalões e isenções em vigor junto da DNRE/Câmara Municipal.\n\nQuando e onde (PRÁTICA — confirmar):\n• O ITI liquida-se antes da transmissão; segundo a informação divulgada, o pagamento faz-se junto da Câmara Municipal em prazo curto (indicado como 3 dias úteis), sem o qual o negócio pode não produzir efeitos.\n• O IPI é anual; a avaliação cabe às comissões de avaliação municipais.\nConfirme prazos, guias e isenções (habitação própria, diáspora) junto da DNRE e da Câmara Municipal competente.\n\nResumo de plataforma — não é aconselhamento fiscal.\n\nSources / Fontes / Bronnen:\n• Lei n.º 54/X/2025 (Código do ITI) e Lei n.º 55/X/2025 (Código do IPI), de 6 de junho — Boletim Oficial, boe.incv.cv\n• Direção Nacional das Receitas do Estado (DNRE), Ministério das Finanças — dnre.gov.cv\n• PwC — Reforma da Tributação do Património (Cabo Verde)\nVerificação necessária / Verification required / Verificatie vereist: confirme taxas e prazos atuais junto da DNRE/Finanças e da Câmara Municipal.","en":"FACT: Since 1 January 2026, the Single Property Tax (IUP) on real estate has been replaced by two new tax codes: the Code of the Property Transfer Tax (ITI) and the Code of the Property Ownership Tax (IPI). The abbreviations ''cITI'' and ''cIPI'' refer to these Codes (''c'' = Código/Code). They were approved by Laws no. 54/X/2025 and no. 55/X/2025 of 6 June and repealed the IUP Code.\n\nWhat each one is:\n• ITI (on purchase): FACT — it applies to the onerous transfer of real estate (sale, exchange, etc.). As a rule the buyer pays it; in an exchange or division, whoever receives the more valuable asset.\n• IPI (annual ownership): FACT — it applies to owning the property; it is due annually by the owner, based on the assessed (patrimonial) value.\n\nRates (confirm): reported figures indicate ITI ~1% (increased up to 3% under privileged regimes) and IPI ~0.1% on buildings and ~0.15% on land, with surcharges for vacant/degraded buildings. Confirm the rates, brackets and exemptions in force with the DNRE / Municipality.\n\nWhen and where (PRACTICE — confirm):\n• ITI is settled before the transfer; per published information, payment is made at the Municipality within a short deadline (reported as 3 working days), without which the deal may not take effect.\n• IPI is annual; valuation is carried out by municipal assessment commissions.\nConfirm deadlines, payment slips and exemptions (own home, diaspora) with the DNRE and the competent Municipality.\n\nPlatform summary — not tax advice.\n\nSources / Fontes / Bronnen:\n• Law no. 54/X/2025 (ITI Code) and Law no. 55/X/2025 (IPI Code), of 6 June — Boletim Oficial, boe.incv.cv\n• National Directorate of State Revenue (DNRE), Ministry of Finance — dnre.gov.cv\n• PwC — Property Taxation Reform (Cape Verde)\nVerificação necessária / Verification required / Verificatie vereist: confirm current rates and deadlines with the DNRE/Finanças and the Municipality.","nl":"FEIT: Sinds 1 januari 2026 is de enkelvoudige vermogensbelasting op onroerend goed (IUP) vervangen door twee nieuwe belastingcodes: de Code van de belasting op de overdracht van onroerend goed (ITI) en de Code van de belasting op het eigendom van onroerend goed (IPI). De afkortingen ''cITI'' en ''cIPI'' verwijzen naar deze Codes (''c'' = Código/Code). Ze zijn goedgekeurd bij Wet nr. 54/X/2025 en nr. 55/X/2025 van 6 juni en hebben de IUP-code ingetrokken.\n\nWat elk is:\n• ITI (bij aankoop): FEIT — geldt bij de overdracht onder bezwarende titel van onroerend goed (koop, ruil, enz.). In de regel betaalt de koper; bij ruil of verdeling degene die het meest waardevolle goed ontvangt.\n• IPI (jaarlijks eigendom): FEIT — geldt voor het bezit van het onroerend goed; jaarlijks verschuldigd door de eigenaar, op basis van de kadastrale (patrimoniale) waarde.\n\nTarieven (verifiëren): gerapporteerde cijfers wijzen op ITI ~1% (verhoogd tot 3% bij bevoorrechte regimes) en IPI ~0,1% op gebouwen en ~0,15% op grond, met toeslagen voor leegstaande/vervallen panden. Bevestig de geldende tarieven, schijven en vrijstellingen bij de DNRE / gemeente.\n\nWanneer en waar (PRAKTIJK — verifiëren):\n• ITI wordt vóór de overdracht voldaan; volgens gepubliceerde informatie gebeurt de betaling bij de gemeente binnen een korte termijn (gemeld als 3 werkdagen), zonder welke de transactie mogelijk geen effect heeft.\n• IPI is jaarlijks; de waardering gebeurt door gemeentelijke taxatiecommissies.\nBevestig termijnen, betaalbewijzen en vrijstellingen (eigen woning, diaspora) bij de DNRE en de bevoegde gemeente.\n\nPlatformsamenvatting — geen belastingadvies.\n\nSources / Fontes / Bronnen:\n• Wet nr. 54/X/2025 (ITI-code) en Wet nr. 55/X/2025 (IPI-code), van 6 juni — Boletim Oficial, boe.incv.cv\n• Nationale Directie van Staatsinkomsten (DNRE), Ministerie van Financiën — dnre.gov.cv\n• PwC — Hervorming van de vermogensbelasting (Kaapverdië)\nVerificação necessária / Verification required / Verificatie vereist: bevestig actuele tarieven en termijnen bij de DNRE/Finanças en de gemeente."}'::jsonb, 'published', now()),
('heranca-e-imoveis-cabo-verde', 'compra', '{"pt":"Herança e imóveis em Cabo Verde","en":"Inheritance and property in Cape Verde","nl":"Erfenis en onroerend goed in Kaapverdië"}'::jsonb, 'Direção-Geral dos Registos, Notariado e Identificação (RNI/DGRNI)', 'summary', 1, 'https://www.rni.cv/', '{"pt":"Enquanto uma herança não é partilhada, o imóvel pertence a todos os herdeiros: ninguém vende sozinho e TODOS têm de assinar. Explicamos a herança indivisa, a habilitação de herdeiros e o registo — confirme sempre no cartório e na Conservatória (RNI).","en":"Until an estate is divided, the property belongs to all heirs: no one sells alone and ALL must sign. We explain the undivided inheritance, the heirs'' qualification and registration — always confirm with the notary and the Land Registry (RNI).","nl":"Zolang een nalatenschap niet is verdeeld, behoort het onroerend goed aan alle erfgenamen: niemand verkoopt alleen en ALLEN moeten tekenen. We leggen de onverdeelde nalatenschap, de erfgenaamverklaring en de registratie uit — bevestig altijd bij de notaris en het Kadaster (RNI)."}'::jsonb, '{"pt":"FACTO: Em Cabo Verde, a sucessão rege-se pelo Código Civil, que fixa a ordem de vocação hereditária (descendentes, ascendentes, cônjuge e colaterais até ao 4.º grau) e protege a legítima dos herdeiros legitimários. Enquanto a herança não for partilhada, pertence a todos os herdeiros em comum — é a herança indivisa.\n\nPorque é um problema ao comprar:\n• FACTO — Nenhum herdeiro pode vender sozinho um imóvel concreto da herança indivisa; a disposição do bem exige o acordo de TODOS os herdeiros. Se um não assinar, a venda não é válida.\n• PRÁTICA (confirmar) — É frequente encontrar imóveis de família sem partilha feita, com herdeiros ausentes ou na diáspora, ou sem sequer a habilitação de herdeiros. Verifique isto antes de qualquer sinal.\n\nPassos habituais (PRÁTICA — confirmar no cartório):\n• Habilitação de herdeiros — ato notarial que identifica quem são os herdeiros.\n• Partilha — por escritura pública no Cartório Notarial se houver acordo e nenhum herdeiro menor/incapaz/ausente; caso contrário, inventário judicial no Tribunal.\n• O cabeça-de-casal administra a herança até à partilha.\n• A transmissão por herança está sujeita a Imposto de Selo (confirmar valores com a DNRE).\n\nRegisto (FACTO/PRÁTICA):\n• Depois da partilha, o imóvel deve ser registado na Conservatória do Registo Predial (RNI/DGRNI), com a escritura, certidão matricial e prova de pagamento dos impostos. Exija a certidão predial atualizada em nome do vendedor antes de comprar.\n\nResumo de plataforma — não é aconselhamento jurídico.\n\nSources / Fontes / Bronnen:\n• Código Civil de Cabo Verde; Código do Notariado\n• Direção-Geral dos Registos, Notariado e Identificação (RNI/DGRNI) — rni.cv; justica.gov.cv\n• Ficha Informativa sobre Direito Sucessório — Cabo Verde (CPLP/CSM, atlascplp.csm.org.pt)\nVerificação necessária / Verification required / Verificatie vereist: confirme o processo, custos e o Imposto de Selo junto do Cartório Notarial, da Conservatória (RNI) e da DNRE.","en":"FACT: In Cape Verde, succession is governed by the Civil Code, which sets the order of heirs (descendants, ascendants, spouse and collaterals up to the 4th degree) and protects the ''legítima'' (reserved portion) of forced heirs. Until the estate is divided, it belongs jointly to all heirs — this is the undivided inheritance (herança indivisa).\n\nWhy it is a problem when buying:\n• FACT — No single heir can sell a specific property from an undivided estate on their own; disposing of the asset requires the agreement of ALL heirs. If one does not sign, the sale is not valid.\n• PRACTICE (confirm) — It is common to find family properties that were never divided, with heirs who are absent or in the diaspora, or without even the heirs'' qualification done. Check this before paying any deposit.\n\nUsual steps (PRACTICE — confirm at the notary):\n• Habilitação de herdeiros — a notarial act identifying who the heirs are.\n• Partilha (division) — by public deed at the Notary if there is agreement and no minor/incapacitated/absent heir; otherwise, judicial inventário at the Court.\n• The cabeça-de-casal (estate administrator) manages the estate until division.\n• Transfer by inheritance is subject to Stamp Duty (Imposto de Selo) — confirm amounts with the DNRE.\n\nRegistration (FACT/PRACTICE):\n• After division, the property must be registered at the Land Registry (Conservatória do Registo Predial, RNI/DGRNI), with the deed, matricial certificate and proof of tax payment. Require an up-to-date land-registry certificate in the seller''s name before buying.\n\nPlatform summary — not legal advice.\n\nSources / Fontes / Bronnen:\n• Civil Code of Cape Verde; Notary Code (Código do Notariado)\n• Directorate-General of Registries, Notary and Identification (RNI/DGRNI) — rni.cv; justica.gov.cv\n• Information Sheet on Succession Law — Cape Verde (CPLP/CSM, atlascplp.csm.org.pt)\nVerificação necessária / Verification required / Verificatie vereist: confirm the process, costs and Stamp Duty with the Notary, the Land Registry (RNI) and the DNRE.","nl":"FEIT: In Kaapverdië wordt erfopvolging geregeld door het Burgerlijk Wetboek (Código Civil), dat de volgorde van erfgenamen vastlegt (afstammelingen, bloedverwanten in opgaande lijn, echtgenoot en zijverwanten tot de 4e graad) en het wettelijk erfdeel (''legítima'') van de dwingende erfgenamen beschermt. Zolang de nalatenschap niet is verdeeld, behoort zij gezamenlijk toe aan alle erfgenamen — dit is de onverdeelde nalatenschap (herança indivisa).\n\nWaarom dit een probleem is bij aankoop:\n• FEIT — Geen enkele erfgenaam kan alleen een concreet onroerend goed uit een onverdeelde nalatenschap verkopen; voor de beschikking is de instemming van ALLE erfgenamen nodig. Tekent er één niet, dan is de verkoop niet geldig.\n• PRAKTIJK (verifiëren) — Vaak zijn familiepanden nooit verdeeld, met erfgenamen die afwezig of in de diaspora zijn, of zonder dat zelfs de erfgenaamverklaring is gedaan. Controleer dit vóór u een aanbetaling doet.\n\nGebruikelijke stappen (PRAKTIJK — bevestig bij de notaris):\n• Habilitação de herdeiros — notariële akte die vaststelt wie de erfgenamen zijn.\n• Verdeling (partilha) — bij notariële akte als er overeenstemming is en geen minderjarige/handelingsonbekwame/afwezige erfgenaam; anders gerechtelijke boedelbeschrijving (inventário) bij de rechtbank.\n• De cabeça-de-casal beheert de nalatenschap tot de verdeling.\n• Overdracht door vererving is onderworpen aan zegelrecht (Imposto de Selo) — bevestig bedragen bij de DNRE.\n\nRegistratie (FEIT/PRAKTIJK):\n• Na de verdeling moet het onroerend goed worden ingeschreven bij het Kadaster (Conservatória do Registo Predial, RNI/DGRNI), met de akte, het kadastraal attest en het betalingsbewijs. Eis vóór aankoop een actueel eigendomsattest op naam van de verkoper.\n\nPlatformsamenvatting — geen juridisch advies.\n\nSources / Fontes / Bronnen:\n• Burgerlijk Wetboek van Kaapverdië; Notariswet (Código do Notariado)\n• Directoraat-generaal Registers, Notariaat en Identificatie (RNI/DGRNI) — rni.cv; justica.gov.cv\n• Informatiefiche Erfrecht — Kaapverdië (CPLP/CSM, atlascplp.csm.org.pt)\nVerificação necessária / Verification required / Verificatie vereist: bevestig de procedure, kosten en het zegelrecht bij de notaris, het Kadaster (RNI) en de DNRE."}'::jsonb, 'published', now()),
('condominio-cabo-verde', 'compra', '{"pt":"Condomínio em Cabo Verde","en":"Condominium in Cape Verde","nl":"Vereniging van eigenaren (condominium) in Kaapverdië"}'::jsonb, 'Direção-Geral dos Registos, Notariado e Identificação (RNI/DGRNI)', 'summary', 1, 'https://boe.incv.cv/', '{"pt":"No condomínio, cada um é dono da sua fração e comproprietário das partes comuns, com quotas para as despesas. As dívidas de condomínio podem afetar quem compra — peça a declaração de dívidas ao administrador. Regime reformado pela Lei n.º 57/X/2025.","en":"In a condominium, each person owns their fraction and co-owns the common parts, with quotas for expenses. Condominium debts can affect the buyer — ask the administrator for a debt declaration. Regime reformed by Law no. 57/X/2025.","nl":"In een condominium bezit ieder zijn eigen kavel en is mede-eigenaar van de gemeenschappelijke delen, met bijdragen voor de kosten. VvE-schulden kunnen de koper raken — vraag de beheerder om een schuldverklaring. Stelsel hervormd bij Wet nr. 57/X/2025."}'::jsonb, '{"pt":"FACTO: A propriedade horizontal (condomínio) em Cabo Verde é regulada pelo Código Civil e foi reformada pela Lei n.º 57/X/2025, de 5 de agosto (Boletim Oficial, I Série n.º 70), em vigor desde 6 de agosto de 2025. O regime define o título constitutivo, as frações autónomas e as partes comuns.\n\nComo funciona:\n• FACTO — Cada condómino é dono exclusivo da sua fração autónoma e comproprietário das partes comuns (entradas, escadas, telhado, elevadores, etc.).\n• Quotas/encargos — Em regra, as despesas de conservação e uso das partes comuns são repartidas pelos condóminos na proporção do valor das suas frações. Confirme os critérios no título constitutivo e no regulamento do condomínio.\n• Administrador — FACTO — gere as partes comuns, cobra as quotas e executa as decisões da assembleia de condóminos. A Lei n.º 57/X/2025 clarificou as competências do administrador e passou a permitir convocatórias e deliberações por meios eletrónicos, reduzindo também para maioria absoluta a alteração do título (antes exigia unanimidade).\n\nDívidas de condomínio ao comprar (PRÁTICA — confirmar):\n• As quotas em atraso são um risco para quem compra: podem gerar litígios e, consoante as regras aplicáveis, afetar a fração. Antes de comprar, peça ao administrador uma declaração de dívidas do condomínio e confirme com o notário quem responde pelos valores em atraso.\n\nResumo de plataforma — não é aconselhamento jurídico.\n\nSources / Fontes / Bronnen:\n• Código Civil de Cabo Verde (regime da propriedade horizontal)\n• Lei n.º 57/X/2025, de 5 de agosto — Boletim Oficial, I Série n.º 70 (boe.incv.cv)\n• Alerta Miranda & Associados sobre a Lei n.º 57/X/2025 (mirandalawfirm.com)\nVerificação necessária / Verification required / Verificatie vereist: confirme as quotas, o título constitutivo e a responsabilidade por dívidas junto do administrador e do notário.","en":"FACT: Horizontal property (condominium) in Cape Verde is governed by the Civil Code and was reformed by Law no. 57/X/2025 of 5 August (Boletim Oficial, I Series no. 70), in force since 6 August 2025. The regime defines the constitutive title, the autonomous fractions and the common parts.\n\nHow it works:\n• FACT — Each condominium owner exclusively owns their autonomous fraction and co-owns the common parts (entrances, stairs, roof, lifts, etc.).\n• Quotas/charges — As a rule, the costs of maintaining and using the common parts are shared among the owners in proportion to the value of their fractions. Confirm the criteria in the constitutive title and the condominium rules.\n• Administrator — FACT — manages the common parts, collects the quotas and carries out the decisions of the owners'' assembly. Law no. 57/X/2025 clarified the administrator''s powers and now allows electronic convocations and deliberations, and lowered the threshold to amend the title to an absolute majority (previously unanimity).\n\nCondominium debts when buying (PRACTICE — confirm):\n• Unpaid quotas are a risk for the buyer: they can cause disputes and, depending on the applicable rules, affect the fraction. Before buying, ask the administrator for a declaration of condominium debts and confirm with the notary who is liable for the arrears.\n\nPlatform summary — not legal advice.\n\nSources / Fontes / Bronnen:\n• Civil Code of Cape Verde (horizontal property regime)\n• Law no. 57/X/2025 of 5 August — Boletim Oficial, I Series no. 70 (boe.incv.cv)\n• Miranda & Associados alert on Law no. 57/X/2025 (mirandalawfirm.com)\nVerificação necessária / Verification required / Verificatie vereist: confirm the quotas, the constitutive title and liability for debts with the administrator and the notary.","nl":"FEIT: Horizontale eigendom (appartementsrecht/condominium) in Kaapverdië wordt geregeld door het Burgerlijk Wetboek en is hervormd bij Wet nr. 57/X/2025 van 5 augustus (Boletim Oficial, I Serie nr. 70), van kracht sinds 6 augustus 2025. Het stelsel omschrijft de constitutieve titel, de autonome kavels (frações) en de gemeenschappelijke delen.\n\nHoe het werkt:\n• FEIT — Elke eigenaar is exclusief eigenaar van zijn autonome kavel en mede-eigenaar van de gemeenschappelijke delen (ingangen, trappen, dak, liften, enz.).\n• Bijdragen/lasten — In de regel worden de kosten voor onderhoud en gebruik van de gemeenschappelijke delen over de eigenaren verdeeld naar rato van de waarde van hun kavels. Bevestig de criteria in de constitutieve titel en het huishoudelijk reglement.\n• Beheerder (administrador) — FEIT — beheert de gemeenschappelijke delen, int de bijdragen en voert de besluiten van de vergadering van eigenaren uit. Wet nr. 57/X/2025 verduidelijkte de bevoegdheden van de beheerder en staat nu elektronische oproepingen en besluiten toe, en verlaagde de drempel voor wijziging van de titel naar een absolute meerderheid (voorheen unanimiteit).\n\nSchulden van de VvE bij aankoop (PRAKTIJK — verifiëren):\n• Achterstallige bijdragen vormen een risico voor de koper: ze kunnen leiden tot geschillen en, afhankelijk van de toepasselijke regels, de kavel raken. Vraag vóór aankoop de beheerder om een verklaring van schulden van het condominium en bevestig bij de notaris wie aansprakelijk is voor de achterstanden.\n\nPlatformsamenvatting — geen juridisch advies.\n\nSources / Fontes / Bronnen:\n• Burgerlijk Wetboek van Kaapverdië (stelsel van horizontale eigendom)\n• Wet nr. 57/X/2025 van 5 augustus — Boletim Oficial, I Serie nr. 70 (boe.incv.cv)\n• Miranda & Associados-alert over Wet nr. 57/X/2025 (mirandalawfirm.com)\nVerificação necessária / Verification required / Verificatie vereist: bevestig de bijdragen, de constitutieve titel en de aansprakelijkheid voor schulden bij de beheerder en de notaris."}'::jsonb, 'published', now())
